import axios, { retryOnErrors } from '@fs/zion-axios'
import { LOG_LEVEL } from '@fs/zion-standards'
import { logFetch } from './logFetch'

// Create a local axios instance for provisional-place to avoid affecting other packages
const provisionalPlaceAxios = axios?.create ? axios.create() : axios
const axiosConfig = { retry: 3 }

// Only configure our local instance if it has the necessary properties (guards against test mocks)
if (
  provisionalPlaceAxios &&
  typeof provisionalPlaceAxios === 'object' &&
  provisionalPlaceAxios.defaults &&
  typeof retryOnErrors === 'function'
) {
  try {
    retryOnErrors(provisionalPlaceAxios, axiosConfig)
  } catch {
    // Silently fail in test environments with incomplete mocks
  }
}

let uniqueId = 0

export function getXRequestId() {
  const now = Date.now()
  return `${now}-${++uniqueId}-places-react`
}

export function getDefaultHeaders() {
  return {
    'Content-Type': 'application/standards-places-v2+json',
    Accept: 'application/json',
    'X-Request-ID': getXRequestId(),
  }
}

export async function doFetchPost(...args) {
  const [
    url,
    body,
    config = { timeout: 60000, headers: getDefaultHeaders(), fsUserAgentChainSuffix: 'zion-provisional-place' },
    logLevelFlag,
  ] = args
  const xRequestId = config?.headers['X-Request-ID']
  const startTime = globalThis.performance.now()
  const pathParamSplit = url.split('?')
  const sPath = pathParamSplit[0]
  const sParameters = pathParamSplit[1] ? `?${pathParamSplit[1]}` : undefined
  try {
    const resp = await provisionalPlaceAxios.post(url, body, config)
    const sRspTimeMS = `${globalThis.performance.now() - startTime}`
    const status = resp.errors ? 'ERROR' : resp.statusMessage
    const error = resp.errors ? JSON.stringify(resp.errors) : undefined
    logFetch({
      method: 'post',
      sPath,
      sParameters,
      sBody: body,
      sRspTimeMS,
      error,
      status,
      logLevel: LOG_LEVEL.INFO,
      logLevelFlag,
      xRequestId,
    })
    return resp
  } catch (err) {
    const status = err.response ? err.response.status : err.status
    const sRspTimeMS = `${globalThis.performance.now() - startTime}`
    const error = err.message || err.statusMessage
    logFetch({
      method: 'post',
      sPath,
      sParameters,
      sBody: body,
      sRspTimeMS,
      error,
      status,
      logLevel: LOG_LEVEL.ERROR,
      logLevelFlag,
      xRequestId,
    })
    throw err
  }
}
