import axios from '@fs/zion-axios'
import zionDebug, { debugVerbose as debugVerboseFactory } from '@fs/zion-debug'
import { i18n } from '@fs/zion-locale'
import { getPlaceOptionsFromApiResponse } from '@fs/zion-standards'
import { doFetchPost, getXRequestId } from './doFetch'

const debug = zionDebug('standards:provisional-place:api-service')
// Guard against test environments where debugVerboseFactory might not be a function
const debugVerbose =
  typeof debugVerboseFactory === 'function' ? debugVerboseFactory('standards:places:useAttributeTypes') : () => {}

export function getDefaultHeaders() {
  return {
    'Content-Type': 'application/standards-places-v2+json',
    Accept: 'application/json',
    'X-Request-ID': getXRequestId(),
  }
}

async function getPlaceSuggestionsFromSearchCriteria(searchCriteria) {
  debug(`fetchPlaceSuggestionsFromSearchCriteria: {searchCriteria: ${searchCriteria}}`)
  try {
    const response = await axios.get(
      `/service/standards/place/ws/places/request?${searchCriteria}&limit=15&output=summary&partial=true`,
      {
        headers: getDefaultHeaders(),
        fsUserAgentChainSuffix: 'zion-provisional-place',
      }
    )
    return getPlaceOptionsFromApiResponse(response)
  } catch (err) {
    debug('Request err:', err?.message)
    // Return empty list of options on error
    return []
  }
}

export async function getProvisionalPlaceDuplicateSuggestions({
  placeName,
  parentPlaceName,
  parentPlaceId,
  placeTypeName,
}) {
  try {
    const textParam = `text=${placeName}`
    const reqParentsParam = parentPlaceId ? `&reqParents=${parentPlaceId}` : ''
    const reqParentsLabelParm = parentPlaceName ? `&reqParentsLabel=${parentPlaceName}` : ''
    const reqTypes = placeTypeName ? `&reqTypes=${placeTypeName}` : ''
    return await getPlaceSuggestionsFromSearchCriteria(textParam + reqParentsParam + reqParentsLabelParm + reqTypes)
  } catch (err) {
    debug('Request err:', err?.message)
    // Return empty list of options on error
    return []
  }
}

export function getAttributeTypes() {
  debugVerbose(`useAttributeTypes.fetchData: {language: ${i18n.language}}`)
  return axios.get(`/service/standards/place/ws/places/attribute-types?acceptLang=${i18n.language}`, {
    headers: getDefaultHeaders(),
    fsUserAgentChainSuffix: 'zion-provisional-place',
  })
}

export async function suggestNewProvisionalPlace({ values, placeType, isProposed, logLevelFlag }) {
  const parentId = values?.parentPlace?.selectedItem?.standard?.id
  const name = values?.placeName
  const locale = values?.placeLang?.code || values?.placeLang?.primaryText
  const type = placeType?.id
  const fromYear = values?.startYear
  const toYear = values?.toYear
  const latitude = values.location ? Number.parseFloat(values.location.split(',')[0]) : Number.NaN
  const longitude = values.location ? Number.parseFloat(values.location.split(',')[1]) : Number.NaN
  const place = values?.place
  const url = values?.webAddress
  const info = values?.info
  const body = {
    parentId,
    name,
    locale,
    type,
    fromYear,
    toYear,
    latitude,
    longitude,
    place,
    url,
    info,
    isProposed,
  }
  const config = {
    headers: {
      'Content-Type': 'application/json',
      Accept: 'application/json',
      'X-Request-ID': getXRequestId(),
    },
  }
  return doFetchPost('/service/standards/place-suggest/suggest', body, config, logLevelFlag)
}

